        - role
        - sizeBytes
        - ramRequiredBytes
        - minTier
        - capabilities
        - tradeoff
      properties:
        id:
          type: string
        displayName:
          type: string
        family:
          type: string
        role:
          type: string
          enum:
            - primary
            - vision
            - embedding
        sizeBytes:
          type: integer
        ramRequiredBytes:
          type: integer
        minTier:
          type: string
          enum:
            - low
            - mid
            - high
            - pro
        capabilities:
          type: array
          items:
            type: string
        tradeoff:
          type: string
        useCaseAxis:
          type: string
          enum:
            - writing
            - code
            - balanced
    ModelInstallPlanEntry:
      type: object
      required:
        - id
        - displayName
        - role
        - sizeBytes
        - ramRequiredBytes
      properties:
        id:
          type: string
        displayName:
          type: string
        role:
          type: string
          enum:
            - primary
            - vision
            - embedding
        sizeBytes:
          type: integer
        ramRequiredBytes:
          type: integer
    ModelInstallPlan:
      type: object
      required:
        - primary
        - companions
        - totalDownloadBytes
        - totalRamBytes
        - fitsHardware
        - tier
        - reason
        - alternatives
      properties:
        primary:
          $ref: '#/components/schemas/ModelCatalogueEntry'
        companions:
          type: array
          items:
            $ref: '#/components/schemas/ModelInstallPlanEntry'
        totalDownloadBytes:
          type: integer
        totalRamBytes:
          type: integer
        fitsHardware:
          type: boolean
        tier:
          type: string
          enum:
            - low
            - mid
            - high
            - pro
        reason:
          type: string
        alternatives:
          type: array
          items:
            $ref: '#/components/schemas/ModelCatalogueEntry'
    MinimumSpecVerdict:
      type: object
